import * as React from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import { getImage } from 'gatsby-plugin-image';
import Box from '@mui/material/Box';
import Layout from '../../components/layout';
import Link from '../../components/common/link';
import SectionMenu from '../../components/sections/menu';
import Thumbnails from '../../components/thumbnails';
import { Seo } from '../../components/seo';
import { works } from '../../libs/works';

const WorksPage = props => {
  const param = new URLSearchParams(props.location.search);
  const category = param.get('category');

  const worksThumbnails = useStaticQuery(graphql`
    {
      allFile(filter: { relativeDirectory: { eq: "works-thumbnails" } }) {
        edges {
          node {
            childImageSharp {
              gatsbyImageData(width: 400, placeholder: BLURRED)
            }
            name
          }
        }
      }
    }
  `);

  const addImageData = ({ name, category, link }) => {
    const [{ node }] = worksThumbnails.allFile.edges.filter(
      worksThumbnail => worksThumbnail.node.name === name
    );

    return {
      name,
      category,
      link,
      image: getImage(node)
    };
  };

  const datas = works.map(work => addImageData(work));

  return (
    <Layout>
      <SectionMenu />
      <Box
        py={10} // header 分
      >
        <Box
          mb={4} // thumbnail の spacing 分
          sx={{
            display: 'flex',
            justifyContent: 'center'
          }}
        >
          {[
            {
              label: 'All',
              link: '/works/'
            },
            {
              label: 'Hotel',
              link: '/works/?category=hotel',
              category: 'hotel'
            },
            {
              label: 'Portrait',
              link: '/works/?category=portrait',
              category: 'portrait'
            }
          ].map(({ label, category: _category }, i) => {
            const link = `/works/${_category ? `?category=${_category}` : ''}`;
            const isCurrent =
              (!category && !_category) || _category === category;

            return (
              <Link
                key={i}
                href={link}
                sx={{
                  mx: 3,
                  textDecoration: isCurrent && 'underline',
                  pointerEvents: isCurrent && 'none'
                }}
              >
                {label}
              </Link>
            );
          })}
        </Box>
        <Thumbnails datas={datas} category={category} />
      </Box>
    </Layout>
  );
};

export default WorksPage;

export const Head = () => {
  return <Seo title='WORKS' />;
};
